    59→    public static <C extends Component, E extends Edge> void read(final BoruvkaFactory<C, E> boruvkaFactory,
    60→            final Queue<C> nodesLoaded) {
    61→
    62→        final Map<Integer, C> nodesMap = new HashMap<>();
    63→        final Map<IntPair, E> edgesMap = new HashMap<>();
    64→
    65→        double totalWeight = 0;
    66→        int edges = 0;
